/**
 * PageListGrouped Component - Display pages grouped by PageGroup
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { ChevronDown, ChevronRight, Plus, Edit, Globe, Clock, FolderPlus, Star } from 'lucide-react';
import Link from 'next/link';
import { GroupPagesModal } from './GroupPagesModal';

interface Page {
  id: string;
  title: string;
  slug: string;
  language: string;
  status: string;
  isDefaultLang: boolean;
  lastSyncedAt: string | null;
  updatedAt: string;
}

interface PageGroup {
  id: string;
  name: string;
  slug: string;
  defaultLanguage: string;
  pages: Page[];
}

interface PageListGroupedProps {
  onAddTranslation?: (pageId: string) => void;
}

export function PageListGrouped({ onAddTranslation }: PageListGroupedProps) {
  const [groups, setGroups] = useState<PageGroup[]>([]);
  const [ungroupedPages, setUngroupedPages] = useState<Page[]>([]);
  const [expandedGroups, setExpandedGroups] = useState<Set<string>>(new Set());
  const [loading, setLoading] = useState(true);
  const [showGroupModal, setShowGroupModal] = useState(false);
  const [settingDefault, setSettingDefault] = useState<string | null>(null);

  useEffect(() => {
    fetchPages();
  }, []);

  const fetchPages = async () => {
    try {
      const timestamp = Date.now();
      const res = await fetch(`/api/admin/pages/grouped?t=${timestamp}`, {
        cache: 'no-store',
        headers: {
          'Cache-Control': 'no-cache'
        }
      });
      const result = await res.json();
      
      if (result.success) {
        setGroups(result.data.groups);
        setUngroupedPages(result.data.ungroupedPages);
        // Expand همه گروهها به صورت پیشفرض
        setExpandedGroups(new Set(result.data.groups.map((g: PageGroup) => g.id)));
      }
    } catch (error) {
      console.error('Error fetching pages:', error);
    } finally {
      setLoading(false);
    }
  };

  const toggleGroup = (groupId: string) => {
    setExpandedGroups(prev => {
      const next = new Set(prev);
      if (next.has(groupId)) {
        next.delete(groupId);
      } else {
        next.add(groupId);
      }
      return next;
    });
  };

  const getLanguageFlag = (lang: string) => {
    const flags: Record<string, string> = {
      en: '🇺🇸',
      ar: '🇸🇦',
      tr: '🇹🇷',
      fr: '🇫🇷',
      de: '🇩🇪',
      es: '🇪🇸'
    };
    return flags[lang] || '🌐';
  };

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      published: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200',
      draft: 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200',
      archived: 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'
    };
    return (
      <span className={`px-2 py-1 text-xs rounded ${colors[status] || colors.draft}`}>
        {status}
      </span>
    );
  };

  const isOutdated = (page: Page) => {
    if (!page.lastSyncedAt) return false;
    const daysSinceSync = Math.floor(
      (Date.now() - new Date(page.lastSyncedAt).getTime()) / (1000 * 60 * 60 * 24)
    );
    return daysSinceSync > 7;
  };

  const handleSetDefault = async (pageId: string) => {
    setSettingDefault(pageId);
    try {
      const token = localStorage.getItem('adminToken');
      const res = await fetch(`/api/admin/pages/${pageId}/set-default`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const result = await res.json();
      if (result.success) {
        fetchPages(); // رفرش لیست
      } else {
        alert(result.error || 'Failed to set default page');
      }
    } catch (error) {
      console.error('Error setting default:', error);
      alert('Failed to set default page');
    } finally {
      setSettingDefault(null);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="text-gray-500">Loading pages...</div>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {groups.map(group => {
        const isExpanded = expandedGroups.has(group.id);
        
        return (
          <div key={group.id} className="border rounded-lg bg-white dark:bg-slate-800 shadow-sm">
            {/* Group Header */}
            <div 
              className="flex items-center justify-between p-4 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
              onClick={() => toggleGroup(group.id)}
            >
              <div className="flex items-center gap-3">
                {isExpanded ? (
                  <ChevronDown size={20} className="text-gray-500" />
                ) : (
                  <ChevronRight size={20} className="text-gray-500" />
                )}
                <span className="text-xl">📁</span>
                <div>
                  <h3 className="font-semibold text-gray-900 dark:text-white">{group.name}</h3>
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    {group.pages.length} language{group.pages.length !== 1 ? 's' : ''} • /{group.slug}
                  </p>
                </div>
              </div>
              
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  const defaultPage = group.pages.find(p => p.isDefaultLang) || group.pages[0];
                  onAddTranslation?.(defaultPage.id);
                }}
                className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors flex items-center gap-1"
              >
                <Plus size={16} />
                Add Translation
              </button>
            </div>

            {/* Pages in Group */}
            {isExpanded && (
              <div className="border-t dark:border-slate-700">
                {group.pages.map(page => (
                  <div 
                    key={page.id}
                    className="flex items-center justify-between p-4 pl-16 hover:bg-gray-50 dark:hover:bg-slate-700 border-b last:border-b-0 dark:border-slate-700 transition-colors"
                  >
                    <div className="flex items-center gap-4 flex-1">
                      <span className="text-2xl">{getLanguageFlag(page.language)}</span>
                      <div className="flex-1">
                        <div className="flex items-center gap-2">
                          <span className="font-medium text-gray-900 dark:text-white">
                            {page.language.toUpperCase()}
                          </span>
                          {page.isDefaultLang && (
                            <span className="text-xs bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200 px-2 py-0.5 rounded flex items-center gap-1">
                              <Star size={12} fill="currentColor" />
                              Default
                            </span>
                          )}
                          {isOutdated(page) && (
                            <span className="text-xs bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200 px-2 py-0.5 rounded flex items-center gap-1">
                              <Clock size={12} />
                              Outdated
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-gray-600 dark:text-gray-400">{page.slug}</p>
                      </div>
                      <div>{getStatusBadge(page.status)}</div>
                    </div>
                    
                    <div className="flex items-center gap-2">
                      {!page.isDefaultLang && (
                        <button
                          type="button"
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            handleSetDefault(page.id);
                          }}
                          disabled={settingDefault === page.id}
                          className="px-2 py-1.5 text-xs border border-gray-300 dark:border-gray-600 rounded hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors flex items-center gap-1 disabled:opacity-50"
                          title="Set as default language"
                        >
                          <Star size={14} />
                          {settingDefault === page.id ? 'Setting...' : 'Set Default'}
                        </button>
                      )}
                      <Link
                        href={`/admin/pages/builder/${page.id}`}
                        className="px-3 py-1.5 text-sm bg-indigo-600 hover:bg-indigo-700 text-white rounded transition-colors flex items-center gap-1"
                      >
                        <Edit size={16} />
                        Builder
                      </Link>
                      <Link
                        href={`/admin/pages/settings/${page.id}`}
                        className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors flex items-center gap-1"
                      >
                        <Edit size={16} />
                        Settings
                      </Link>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}

      {/* Ungrouped Pages */}
      {ungroupedPages.length > 0 && (
        <div className="border rounded-lg bg-white dark:bg-slate-800 shadow-sm">
          <div className="p-4 border-b dark:border-slate-700 flex items-center justify-between">
            <h3 className="font-semibold text-gray-900 dark:text-white flex items-center gap-2">
              <Globe size={20} />
              Ungrouped Pages ({ungroupedPages.length})
            </h3>
            <button
              onClick={() => setShowGroupModal(true)}
              className="px-3 py-1.5 text-sm bg-indigo-600 hover:bg-indigo-700 text-white rounded transition-colors flex items-center gap-1"
            >
              <FolderPlus size={16} />
              Create Group
            </button>
          </div>
          <div>
            {ungroupedPages.map(page => (
              <div 
                key={page.id}
                className="flex items-center justify-between p-4 hover:bg-gray-50 dark:hover:bg-slate-700 border-b last:border-b-0 dark:border-slate-700 transition-colors"
              >
                <div className="flex items-center gap-4 flex-1">
                  <span className="text-2xl">{getLanguageFlag(page.language)}</span>
                  <div className="flex-1">
                    <div className="font-medium text-gray-900 dark:text-white">{page.title}</div>
                    <p className="text-sm text-gray-600 dark:text-gray-400">{page.slug}</p>
                  </div>
                  <div>{getStatusBadge(page.status)}</div>
                </div>
                
                <div className="flex items-center gap-2">
                  <Link
                    href={`/admin/pages/builder/${page.id}`}
                    className="px-3 py-1.5 text-sm bg-indigo-600 hover:bg-indigo-700 text-white rounded transition-colors flex items-center gap-1"
                  >
                    <Edit size={16} />
                    Builder
                  </Link>
                  <Link
                    href={`/admin/pages/settings/${page.id}`}
                    className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors flex items-center gap-1"
                  >
                    <Edit size={16} />
                    Settings
                  </Link>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {groups.length === 0 && ungroupedPages.length === 0 && (
        <div className="text-center py-12 text-gray-500 dark:text-gray-400">
          No pages found. Create your first page!
        </div>
      )}

      {/* Group Pages Modal */}
      <GroupPagesModal
        isOpen={showGroupModal}
        onClose={() => setShowGroupModal(false)}
        onSuccess={() => {
          setShowGroupModal(false);
          fetchPages();
        }}
        ungroupedPages={ungroupedPages}
      />
    </div>
  );
}
